    private JdbcTemplate jdbcTemplate;

    @Autowired
    private KafkaTemplate<String, String> kafkaTemplate;

    public void initiateOrderSaga(OrderRequest request) {
        try (TransactionStatus status = transactionManager.getTransaction(new DefaultTransactionDefinition())) {
            // Step 1: Place Order
            String orderId = orderPlacementService.placeOrder(request);

            // Write to outbox table
            jdbcTemplate.update("INSERT INTO order_outbox (id, saga_id, event_type, payload) VALUES (?, ?, ?, ?)",
                UUID.randomUUID(), UUID.randomUUID().toString(), "ORDER_PLACED", new ObjectMapper().writeValueAsString(new OrderPlacedEvent(orderId)));

            // Send message with Kafka transactional producer
            kafkaTemplate.send("order_events", orderId, new ObjectMapper().writeValueAsString(new OrderPlacedEvent(orderId)));

            transactionManager.commit(status);  // Commit the transaction
        } catch (Exception e) {
            transactionManager.rollback(status);  // Rollback the transaction on failure
            throw new RuntimeException("Failed to place order", e);
        }
    }

    private void cancelOrderSaga(String orderId) throws Exception {
        try (TransactionStatus status = transactionManager.getTransaction(new DefaultTransactionDefinition())) {
            // Compensate Step 4: Abort Fulfillment
            orderFulfillmentService.abortFulfillment(orderId);

            // Write to outbox table for compensation events
            jdbcTemplate.update("INSERT INTO order_outbox (id, saga_id, event_type, payload) VALUES (?, ?, ?, ?)",
                UUID.randomUUID(), UUID.randomUUID().toString(), "ORDER_ABORTED", new ObjectMapper().writeValueAsString(new OrderAbortedEvent(orderId)));

            // Send message with Kafka transactional producer for compensation events
            kafkaTemplate.send("order_events", orderId, new ObjectMapper().writeValueAsString(new OrderAbortedEvent(orderId)));

            transactionManager.commit(status);  // Commit the transaction
        } catch (Exception e) {
            transactionManager.rollback(status);  // Rollback the transaction on failure
            throw new RuntimeException("Failed to compensate order", e);
        }
    }

    private void publishEvent(OrderPlacedEvent event) {
        String sagaId = UUID.randomUUID().toString();

        jdbcTemplate.update("INSERT INTO order_outbox (id, saga_id, event_type, payload) VALUES (?, ?, ?, ?)",
            UUID.randomUUID(), sagaId, "ORDER_PLACED", new ObjectMapper().writeValueAsString(event));

        kafkaTemplate.send("order_events", sagaId, event.toJson());
    }
}
```

#### Step 3: Consumer Logic with EOS

Ensure that consumers process messages from Kafka within their own transactions.

