            OrderPlacedEvent orderEvent = new ObjectMapper().readValue(event, OrderPlacedEvent.class);

            // Business logic to fulfill the order

            if (fulfillOrder(orderEvent)) {
                jdbcTemplate.update("UPDATE orders SET status='FULFILLED' WHERE id=?", orderEvent.getOrderId());

                // Mark event as processed in outbox table
                jdbcTemplate.update("UPDATE order_outbox SET processed = TRUE WHERE saga_id = ?", orderEvent.getSagaId());

                transactionManager.commit(status);  // Commit the transaction
            } else {
                transactionManager.rollback(status);  // Rollback the transaction on failure
            }
        } catch (Exception e) {
